create or replace function public.get_jobs_overview() returns jsonb language sql stable security definer set search_path = public as 'select jsonb_build_object(''schoolCount'', coalesce((select count(distinct school_name) from public.job_data where credibility in (''高'', ''中'') and verification_status in (''verified'', ''reviewed'')), 0), ''majorCount'', coalesce((select count(distinct major_name) from public.job_data where credibility in (''高'', ''中'') and verification_status in (''verified'', ''reviewed'')), 0), ''recordCount'', coalesce((select count(*) from public.job_data where credibility in (''高'', ''中'') and verification_status in (''verified'', ''reviewed'')), 0), ''byCategory'', coalesce((select jsonb_agg(row_to_json(x) order by x.record_count desc) from (select coalesce(mp.discipline_category, ''未分类'') as category, count(*) as record_count from public.job_data jd left join public.major_profiles mp on jd.major_code = mp.major_code or jd.major_name = mp.major_name where jd.credibility in (''高'', ''中'') and jd.verification_status in (''verified'', ''reviewed'') group by coalesce(mp.discipline_category, ''未分类'')) x), ''[]''::jsonb), ''latestRecords'', coalesce((select jsonb_agg(to_jsonb(j) order by j.created_at desc, j.id desc) from (select * from public.job_data where credibility in (''高'', ''中'') and verification_status in (''verified'', ''reviewed'') order by created_at desc, id desc limit 50) j), ''[]''::jsonb));';
